export type Cell = [number, number];

const NEIGHBORS_TO_SURVIVE = 2;
const NEIGHBORS_TO_BIRTH = 3;

const cellKey = (x: number, y: number): string => `${x},${y}`;

const parseCellKey = (k: string): Cell => {
  const [xs, ys] = k.split(",");
  return [Number(xs), Number(ys)];
};

const countLiveNeighbors = (cells: Cell[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (const [nx, ny] of neighborPositions(x, y)) {
      const k = cellKey(nx, ny);
      counts.set(k, (counts.get(k) ?? 0) + 1);
    }
  }
  return counts;
};

const neighborPositions = function* (x: number, y: number): Generator<Cell> {
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      yield [x + dx, y + dy];
    }
  }
};

const survives = (neighborCount: number, isAlive: boolean): boolean =>
  neighborCount === NEIGHBORS_TO_BIRTH ||
  (neighborCount === NEIGHBORS_TO_SURVIVE && isAlive);

export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(([x, y]) => cellKey(x, y)));
  const neighborCounts = countLiveNeighbors(cells);

  const next: Cell[] = [];
  for (const [k, count] of neighborCounts) {
    if (survives(count, alive.has(k))) {
      next.push(parseCellKey(k));
    }
  }
  return next;
}
